// Redeyed Sentinel shared helpers. Defined once (guarded) so the per-form
// render/verify hooks stay tiny. vB::getDatastore() and $_SERVER are available
// on every page via global.php.
if (!function_exists('redeyed_sentinel_opt')) {
    function redeyed_sentinel_opt($name) {
        return trim((string) vB::getDatastore()->getOption('redeyed_sentinel_' . $name));
    }
}
if (!function_exists('redeyed_sentinel_base_url')) {
    function redeyed_sentinel_base_url() {
        $u = redeyed_sentinel_opt('base_url');
        if ($u === '') { $u = 'https://redeyed.com'; }
        return rtrim($u, '/');
    }
}
if (!function_exists('redeyed_sentinel_widget_html')) {
    function redeyed_sentinel_widget_html() {
        $site = redeyed_sentinel_opt('site_key');
        if ($site === '') { return ''; }
        $siteEsc = htmlspecialchars($site, ENT_QUOTES, 'UTF-8');
        $baseEsc = htmlspecialchars(redeyed_sentinel_base_url(), ENT_QUOTES, 'UTF-8');
        $map = array('widget' => 'data-widget', 'theme' => 'data-theme', 'scheme' => 'data-scheme', 'difficulty' => 'data-difficulty', 'width' => 'data-width');
        $attrs = '';
        foreach ($map as $opt => $attr) {
            $v = redeyed_sentinel_opt($opt);
            if ($v !== '') { $attrs .= ' ' . $attr . '="' . htmlspecialchars($v, ENT_QUOTES, 'UTF-8') . '"'; }
        }
        return "\n<!-- Redeyed Sentinel -->\n"
            . '<div class="redeyed-sentinel" style="margin:10px 0;">'
            . '<script src="' . $baseEsc . '/sentinel.js" async></script>'
            . '<div class="sentinel-captcha" data-sitekey="' . $siteEsc . '"' . $attrs . '></div>'
            . "</div>\n<!-- /Redeyed Sentinel -->\n";
    }
}
if (!function_exists('redeyed_sentinel_client_ip')) {
    function redeyed_sentinel_client_ip() {
        $sources = array('HTTP_CF_CONNECTING_IP', 'HTTP_X_FORWARDED_FOR', 'HTTP_X_REAL_IP', 'REMOTE_ADDR');
        foreach ($sources as $key) {
            if (empty($_SERVER[$key])) { continue; }
            $c = (string) $_SERVER[$key];
            if (strpos($c, ',') !== false) { $parts = explode(',', $c); $c = trim($parts[0]); } else { $c = trim($c); }
            if ($c !== '' && filter_var($c, FILTER_VALIDATE_IP) !== false) { return $c; }
        }
        return '';
    }
}
if (!function_exists('redeyed_sentinel_log_block')) {
    function redeyed_sentinel_log_block($form, $ip, $outcome, $score) {
        if ((int) vB::getDatastore()->getOption('redeyed_sentinel_log_blocks') !== 1) { return; }
        global $vbulletin;
        if (empty($vbulletin->db) || !is_object($vbulletin->db)) { return; }
        $db = $vbulletin->db;
        try {
            // Lazily create the log table (a single product XML cannot run
            // install SQL reliably across vB4/vB5, so create on first use).
            $db->query_write("CREATE TABLE IF NOT EXISTS " . TABLE_PREFIX . "redeyed_sentinel_log (
                logid INT UNSIGNED NOT NULL AUTO_INCREMENT,
                form VARCHAR(20) NOT NULL DEFAULT '',
                ipaddress VARCHAR(45) NOT NULL DEFAULT '',
                outcome VARCHAR(40) NOT NULL DEFAULT '',
                score FLOAT NULL,
                dateline INT UNSIGNED NOT NULL DEFAULT 0,
                PRIMARY KEY (logid),
                KEY dateline (dateline)
            ) ENGINE=InnoDB");
            $db->query_write(sprintf(
                "INSERT INTO " . TABLE_PREFIX . "redeyed_sentinel_log (form, ipaddress, outcome, score, dateline) VALUES ('%s', '%s', '%s', %s, %d)",
                $db->escape_string(substr($form, 0, 20)),
                $db->escape_string(substr($ip, 0, 45)),
                $db->escape_string(substr($outcome, 0, 40)),
                ($score === null ? 'NULL' : (float) $score),
                (defined('TIMENOW') ? TIMENOW : time())
            ));
        } catch (Exception $e) {
            // Logging must never break verification.
        }
    }
}
if (!function_exists('redeyed_sentinel_check')) {
    // Verify the posted token for $form. Returns true if passed (or inert),
    // false if blocked (after logging). Fail-open when no Secret Key is set.
    function redeyed_sentinel_check($form) {
        $secret = redeyed_sentinel_opt('secret_key');
        if ($secret === '') { return true; }

        global $vbulletin;
        $token = '';
        if (isset($vbulletin->input) && is_object($vbulletin->input)) {
            $token = (string) $vbulletin->input->clean_gpc('p', 'sentinel-token', TYPE_NOHTML);
        }
        if ($token === '' && isset($_POST['sentinel-token'])) {
            $token = (string) $_POST['sentinel-token'];
        }

        $ip = redeyed_sentinel_client_ip();
        $outcome = 'missing_token';
        $score = null;
        $passed = false;

        if ($token !== '' && function_exists('curl_init')) {
            $outcome = 'error';
            $body = array('secret' => $secret, 'response' => $token);
            if ($ip !== '') { $body['remoteip'] = $ip; }

            $ch = curl_init();
            curl_setopt($ch, CURLOPT_URL, redeyed_sentinel_base_url() . '/sentinel/siteverify');
            curl_setopt($ch, CURLOPT_POST, true);
            curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($body));
            curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
            curl_setopt($ch, CURLOPT_TIMEOUT, 10);
            curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 5);
            curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, true);
            curl_setopt($ch, CURLOPT_SSL_VERIFYHOST, 2);
            curl_setopt($ch, CURLOPT_HTTPHEADER, array('Content-Type: application/json', 'Accept: application/json'));

            $resp   = curl_exec($ch);
            $errno  = curl_errno($ch);
            $status = (int) curl_getinfo($ch, CURLINFO_HTTP_CODE);
            curl_close($ch);

            if ($errno === 0 && $resp !== false && $status >= 200 && $status < 300) {
                $d = json_decode($resp, true);
                if (is_array($d)) {
                    $passed  = isset($d['success']) && $d['success'] === true;
                    $outcome = isset($d['outcome']) ? (string) $d['outcome'] : '';
                    $score   = isset($d['score']) ? (float) $d['score'] : null;
                }
            }
        }

        if (!$passed) {
            redeyed_sentinel_log_block($form, $ip, $outcome, $score);
        }

        return $passed;
    }
}
if (!function_exists('redeyed_sentinel_block')) {
    // Push the failure error into whatever error channel the current form uses.
    function redeyed_sentinel_block() {
        $msg = 'Sentinel verification failed. Please complete the verification challenge and try again.';
        if (isset($GLOBALS['errors']) && is_array($GLOBALS['errors'])) { $GLOBALS['errors'][] = $msg; }
        if (isset($GLOBALS['register_errors']) && is_array($GLOBALS['register_errors'])) { $GLOBALS['register_errors'][] = $msg; }
        if (class_exists('vB_Exception_Api')) { throw new vB_Exception_Api(array('{1}', $msg)); }
        if (empty($GLOBALS['errors']) && empty($GLOBALS['register_errors'])) {
            if (function_exists('standard_error')) { standard_error($msg); } else { die($msg); }
        }
    }
}

if ((int) vB::getDatastore()->getOption('redeyed_sentinel_protect_register') === 1) {
    $rs_widget = function_exists('redeyed_sentinel_widget_html') ? redeyed_sentinel_widget_html() : '';
    if ($rs_widget !== '') {
        if (isset($templater) && is_object($templater)) { $templater->register('redeyed_sentinel_widget', $rs_widget); }
        if (isset($templater_register) && is_object($templater_register)) { $templater_register->register('redeyed_sentinel_widget', $rs_widget); }
        if (isset($pagetext) && is_string($pagetext)) { $pagetext .= $rs_widget; }
        if (isset($HTML) && is_string($HTML)) {
            $HTML = (strpos($HTML, '</form>') !== false) ? preg_replace('#</form>#', $rs_widget . '</form>', $HTML, 1) : $HTML . $rs_widget;
        }
        if (isset($data) && is_array($data)) { $data['redeyed_sentinel_widget'] = $rs_widget; }
    }
}

if ((int) vB::getDatastore()->getOption('redeyed_sentinel_protect_lostpw') === 1) {
    $rs_widget = function_exists('redeyed_sentinel_widget_html') ? redeyed_sentinel_widget_html() : '';
    if ($rs_widget !== '') {
        if (isset($templater) && is_object($templater)) { $templater->register('redeyed_sentinel_widget', $rs_widget); }
        if (isset($HTML) && is_string($HTML)) {
            $HTML = (strpos($HTML, '</form>') !== false) ? preg_replace('#</form>#', $rs_widget . '</form>', $HTML, 1) : $HTML . $rs_widget;
        }
        if (isset($pagetext) && is_string($pagetext)) { $pagetext .= $rs_widget; }
    }
}

if ((int) vB::getDatastore()->getOption('redeyed_sentinel_protect_contact') === 1) {
    $rs_widget = function_exists('redeyed_sentinel_widget_html') ? redeyed_sentinel_widget_html() : '';
    if ($rs_widget !== '') {
        if (isset($templater) && is_object($templater)) { $templater->register('redeyed_sentinel_widget', $rs_widget); }
        if (isset($HTML) && is_string($HTML)) {
            $HTML = (strpos($HTML, '</form>') !== false) ? preg_replace('#</form>#', $rs_widget . '</form>', $HTML, 1) : $HTML . $rs_widget;
        }
        if (isset($pagetext) && is_string($pagetext)) { $pagetext .= $rs_widget; }
    }
}

// Only verify an actual send (POST), not the initial form display.
if ((int) vB::getDatastore()->getOption('redeyed_sentinel_protect_contact') === 1
    && (isset($_POST['do']) && $_POST['do'] === 'mail')
    && function_exists('redeyed_sentinel_check') && !redeyed_sentinel_check('contact')) {
    redeyed_sentinel_block();
}
